//! Qwen3-TTS speech-tokenizer DECODER (codec tokens → 24 kHz waveform).
//!
//! Faithful CPU/f32 port of the `Qwen3TTSTokenizerV2Model` decoder half (the
//! `decoder.*` tensors of `speech_tokenizer/model.safetensors`). The encoder
//! half is speech-IN and is NOT needed for TTS, so it is intentionally absent.
//!
//! This is the net-new "vocoder" for the gnosis distributed-inference TTS path.
//! The talker LM (Qwen3 backbone, `talker.*` in the root `model.safetensors`)
//! emits, per 12.5 Hz frame, `num_code_groups = 16` residual-VQ codes (codebook
//! size 2048). This module turns a `[n_frames, 16]` code matrix into a mono f32
//! PCM waveform at 24 000 Hz. The total upsampling factor is
//!   decode_upsample_rate = 1920  =  decoder.upsample (2×2) · decoder.decoder (8·5·4·3),
//! so 12.5 Hz frames × 1920 = 24 000 Hz. (See speech_tokenizer/config.json.)
//!
//! Pipeline (matches the HF reference forward, deterministic — NO diffusion):
//!   1. RVQ dequantize: for each of 16 code groups, gather the codebook vector
//!      (`embedding_sum / cluster_usage`, EMA-codebook), sum the residuals →
//!      latent_q [n_frames, 256]. Group 0 uses `rvq_first`; groups 1..16 use
//!      `rvq_rest.layers.{0..14}`. Each RVQ has input_proj/output_proj (1×1 conv).
//!   2. pre_conv: conv1d 512→1024 (k3, causal pad 2). [Quantizer output_proj
//!      lifts 256→512; pre_conv lifts 512→1024.]
//!   3. pre_transformer: input_proj 1024→512, 8 Qwen3-style RMSNorm/GQA/SwiGLU
//!      layers with per-sublayer LayerScale, output_proj 512→1024.
//!   4. upsample: 2 stages, each = conv_transpose1d(stride 2) + a ConvNeXt block
//!      (depthwise conv k7 → LayerNorm → pwconv1 → GELU → pwconv2 → ·gamma + res).
//!   5. decoder (SEANet): block0 conv 1024→1536 (k7); blocks 1..4 each =
//!      Snake → conv_transpose1d upsample (strides 8,5,4,3) → 3 residual units
//!      (Snake → dilated conv k7 → Snake → conv k1 + residual); block5 Snake;
//!      block6 conv 96→1 (k7) → waveform.
//!
//! Snake activation: snake(x) = x + (1/α)·sin²(α·x)  (per-channel α, plus a β
//! gain in some impls). The decoder.decoder Snake carries `alpha` and `beta`
//! tensors; we apply the standard Snake-beta:
//!   snake(x) = x + (1/(β+ε))·sin²(α·x).
//!
//! Weight naming (written by encode-knot.py with the `qwen3_tts` branch; the
//! KnotWriter joins `.`→`_`, so e.g. `decoder.pre_conv.conv.weight` becomes
//! `tts_codec_pre_conv_conv_weight`). All names are prefixed `tts_codec_` to
//! ride alongside the talker text backbone in the same knot, exactly like the
//! `vit_*` carry for Qwen2.5-VL.
//!
//! Verified against forkjoin-ai/qwen3-tts-12hz-0.6b-base speech_tokenizer
//! safetensors header (2026-05-24): 496 tensors, all decoder.* shapes matched.

use std::sync::Arc;

use crate::loader::WeightBackend;
use crate::math::{gelu_inplace, mat_vec_f32, rms_norm, softmax};
use crate::math_pneuma::{conv1d_dilated, conv1d_out_len_dilated, conv_transpose1d};

const PFX: &str = "tts_codec_";

// ─────────────────────────────────────────────────────────────────────────────
// Config (sourced from speech_tokenizer/config.json; falls back to the 12hz-0.6b
// values). All structural; no learned hyperparameters.
// ─────────────────────────────────────────────────────────────────────────────

#[derive(Debug, Clone)]
pub struct Qwen3TtsCodecConfig {
    /// Frame rate of the codec tokens (12.5 Hz).
    pub frame_rate: f32,
    /// Output PCM sample rate (24 000 Hz).
    pub sample_rate: usize,
    /// Total codes per frame = num_code_groups (16). Group 0 → rvq_first,
    /// groups 1..16 → rvq_rest.layers.{0..14}.
    pub num_quantizers: usize,
    /// Codebook size per group (2048).
    pub codebook_size: usize,
    /// Codebook vector dim (256).
    pub codebook_dim: usize,
    /// RVQ projected latent dim (512) — output of output_proj.
    pub latent_dim: usize,
    /// pre_transformer hidden (512) and layer count (8).
    pub pre_tf_hidden: usize,
    pub pre_tf_layers: usize,
    pub pre_tf_heads: usize,
    pub pre_tf_kv_heads: usize,
    pub pre_tf_head_dim: usize,
    pub pre_tf_inter: usize,
    /// Decoder hidden after pre_conv / before SEANet (1024).
    pub decoder_in: usize,
    /// ConvNeXt upsample strides (2, 2).
    pub upsample_strides: Vec<usize>,
    /// SEANet upsample strides (8, 5, 4, 3) → kernels 2·stride.
    pub seanet_strides: Vec<usize>,
    /// SEANet residual-unit dilations within each block (1, 3, 9 — three units).
    pub seanet_dilations: Vec<usize>,
    pub rms_norm_eps: f32,
    pub rope_theta: f32,
}

impl Default for Qwen3TtsCodecConfig {
    fn default() -> Self {
        Self {
            frame_rate: 12.5,
            sample_rate: 24_000,
            num_quantizers: 16,
            codebook_size: 2048,
            codebook_dim: 256,
            latent_dim: 512,
            pre_tf_hidden: 512,
            pre_tf_layers: 8,
            pre_tf_heads: 16,
            pre_tf_kv_heads: 16,
            pre_tf_head_dim: 64,
            pre_tf_inter: 1024,
            decoder_in: 1024,
            upsample_strides: vec![2, 2],
            seanet_strides: vec![8, 5, 4, 3],
            // SEANet residual-unit dilations: the reference decoder hard-codes
            // [1, 3, 9] for the three residual units per block (verified against
            // qwen3-tts.cpp apply_decoder_block: res[0]=1, res[1]=3, res[2]=9).
            seanet_dilations: vec![1, 3, 9],
            rms_norm_eps: 1e-5,
            rope_theta: 10_000.0,
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Decoder
// ─────────────────────────────────────────────────────────────────────────────

pub struct Qwen3TtsCodecDecoder {
    cfg: Qwen3TtsCodecConfig,
    backend: Arc<dyn WeightBackend>,
}

impl Qwen3TtsCodecDecoder {
    pub fn new(cfg: Qwen3TtsCodecConfig, backend: Arc<dyn WeightBackend>) -> Self {
        Self { cfg, backend }
    }

    /// Returns true iff the knot actually carried the codec decoder. Lets the
    /// probe fail fast with a clear "re-encode with qwen3_tts branch" message.
    pub fn is_present(backend: &Arc<dyn WeightBackend>) -> bool {
        backend.has_tensor(&format!("{PFX}decoder_0_conv_weight"))
    }

    pub fn sample_rate(&self) -> usize {
        self.cfg.sample_rate
    }

    /// Decode a `[n_frames, num_quantizers]` code matrix (row-major, u32 codes)
    /// to a mono f32 PCM waveform at `sample_rate`. Output length is
    /// `n_frames * 1920` (decode_upsample_rate), minus causal-conv edge effects
    /// (HF trims to exactly n_frames*1920 via the causal pad scheme; we match by
    /// using causal left-pad on every conv).
    pub fn decode(&self, codes: &[u32], n_frames: usize) -> Result<Vec<f32>, String> {
        let cfg = &self.cfg;
        if codes.len() != n_frames * cfg.num_quantizers {
            return Err(format!(
                "decode: codes len {} != n_frames*nq {}*{}={}",
                codes.len(),
                n_frames,
                cfg.num_quantizers,
                n_frames * cfg.num_quantizers
            ));
        }
        if n_frames == 0 {
            return Err("decode: n_frames == 0".into());
        }

        // 1. RVQ dequantize → latent [latent_dim, n_frames] (channel-major, the
        //    layout the conv stack wants).
        let latent = self.dequantize_rvq(codes, n_frames)?; // [512, n_frames]

        // 2. pre_conv: 512→1024, k3, causal pad 2 then trim to n_frames.
        let mut x = self.causal_conv1d(
            &latent,
            &format!("{PFX}pre_conv_conv"),
            cfg.latent_dim,
            cfg.decoder_in,
            n_frames,
            3,
            1,
            1,
        )?; // [1024, n_frames]

        // 3. pre_transformer (operates on [n_frames, 1024]).
        x = self.pre_transformer(&x, n_frames)?; // [1024, n_frames]

        // 4. upsample (ConvNeXt) stages: each doubles the time axis.
        let mut cur_len = n_frames;
        let ch = cfg.decoder_in;
        let strides = cfg.upsample_strides.clone();
        for (si, &stride) in strides.iter().enumerate() {
            let (nx, nlen) = self.upsample_stage(&x, si, ch, cur_len, stride)?;
            x = nx;
            cur_len = nlen;
            // channels unchanged (1024→1024 per the headers).
        }
        // After upsample: ch=1024, cur_len = n_frames*4.

        // 5. SEANet decoder.
        let wav = self.seanet_decode(&x, ch, cur_len)?;
        Ok(wav)
    }

    // ── 1. RVQ dequantize ──────────────────────────────────────────────────
    //
    // For each frame f and code group g, look up codebook vector
    //   cb[code] = embedding_sum[code] / max(cluster_usage[code], eps)
    // (EMA codebook normalisation, the Encodec/Mimi convention). rvq_first
    // handles group 0; rvq_rest.vq.layers.{0..14} handle groups 1..16.
    //
    // FAITHFUL to the HF/reference SplitResidualVectorQuantizer.decode (verified
    // against QwenLM/Qwen3-TTS speech_tokenizer + the qwen3-tts.cpp port):
    //   first_emb  = rvq_first.vq.layers[0].decode(codes[0])      # [256, T]
    //   first_proj = rvq_first.output_proj(first_emb)             # [512, T]
    //   rest_sum   = Σ_{i=0..14} rvq_rest.layers[i].decode(c[i+1])# [256, T]
    //   rest_proj  = rvq_rest.output_proj(rest_sum)               # [512, T]
    //   latent     = first_proj + rest_proj                       # [512, T]
    //
    // CRITICAL: group-0 is projected through rvq_first's OWN output_proj, NOT
    // rvq_rest's. The two projection matrices are distinct (confirmed: different
    // tensors in both safetensors + knot). Folding group-0 into the rest-sum and
    // projecting through rvq_rest (the previous bug) routes the semantic/first
    // codebook through the wrong linear map → garbage latent → non-speech audio.
    // (semantic_codebook_size:4096 in the config is the ENCODER's WavLM teacher
    // codebook; the DECODER's rvq_first is a plain 2048×256 RVQ bank, so the
    // codebook dims here are correct as-is.)
    fn dequantize_rvq(&self, codes: &[u32], n_frames: usize) -> Result<Vec<f32>, String> {
        let cfg = &self.cfg;
        let cd = cfg.codebook_dim; // 256
        let eps = 1e-5f32; // EMA cluster-usage floor (reference uses 1e-5)

        // ── group 0 (rvq_first): dequantize into code-space [cd, n_frames] ──
        let mut first_emb = vec![0.0f32; cd * n_frames];
        {
            let (emb_name, usage_name) = self.rvq_codebook_names(0);
            let emb = self.fetch_f32(&emb_name)?; // [codebook_size, cd]
            let usage = self.fetch_f32(&usage_name)?; // [codebook_size]
            if emb.len() != cfg.codebook_size * cd {
                return Err(format!(
                    "{emb_name}: len {} != codebook_size*cd {}",
                    emb.len(),
                    cfg.codebook_size * cd
                ));
            }
            for f in 0..n_frames {
                let code = codes[f * cfg.num_quantizers] as usize;
                if code >= cfg.codebook_size {
                    return Err(format!(
                        "code {code} (frame {f}, group 0) >= codebook_size {}",
                        cfg.codebook_size
                    ));
                }
                let row = &emb[code * cd..(code + 1) * cd];
                let denom = usage[code].max(eps);
                for c in 0..cd {
                    first_emb[c * n_frames + f] = row[c] / denom;
                }
            }
        }

        // ── groups 1..16 (rvq_rest): sum residuals in code-space [cd, n_frames] ──
        let mut rest_sum = vec![0.0f32; cd * n_frames];
        for g in 1..cfg.num_quantizers {
            let (emb_name, usage_name) = self.rvq_codebook_names(g);
            let emb = self.fetch_f32(&emb_name)?; // [codebook_size, cd]
            let usage = self.fetch_f32(&usage_name)?; // [codebook_size]
            if emb.len() != cfg.codebook_size * cd {
                return Err(format!(
                    "{emb_name}: len {} != codebook_size*cd {}",
                    emb.len(),
                    cfg.codebook_size * cd
                ));
            }
            for f in 0..n_frames {
                let code = codes[f * cfg.num_quantizers + g] as usize;
                if code >= cfg.codebook_size {
                    return Err(format!(
                        "code {code} (frame {f}, group {g}) >= codebook_size {}",
                        cfg.codebook_size
                    ));
                }
                let row = &emb[code * cd..(code + 1) * cd];
                let denom = usage[code].max(eps);
                for c in 0..cd {
                    rest_sum[c * n_frames + f] += row[c] / denom;
                }
            }
        }

        // ── project each through its OWN output_proj (1×1 conv cd→latent_dim) and add ──
        let first_proj = self.fetch_f32(&format!("{PFX}quantizer_rvq_first_output_proj_weight"))?;
        let rest_proj = self.fetch_f32(&format!("{PFX}quantizer_rvq_rest_output_proj_weight"))?;
        // weight [512, 256, 1] → flatten to [512, 256]; out[oc] = Σ_ic w[oc,ic]·x[ic].
        let ld = cfg.latent_dim;
        let mut latent = vec![0.0f32; ld * n_frames];
        for f in 0..n_frames {
            for oc in 0..ld {
                let wrow = oc * cd;
                let mut s = 0.0f32;
                for ic in 0..cd {
                    s += first_proj[wrow + ic] * first_emb[ic * n_frames + f]
                        + rest_proj[wrow + ic] * rest_sum[ic * n_frames + f];
                }
                latent[oc * n_frames + f] = s;
            }
        }
        Ok(latent)
    }

    fn rvq_codebook_names(&self, group: usize) -> (String, String) {
        // group 0 → rvq_first.vq.layers.0; groups 1..16 → rvq_rest.vq.layers.{g-1}.
        if group == 0 {
            (
                format!("{PFX}quantizer_rvq_first_vq_layers_0__codebook_embedding_sum"),
                format!("{PFX}quantizer_rvq_first_vq_layers_0__codebook_cluster_usage"),
            )
        } else {
            let l = group - 1;
            (
                format!("{PFX}quantizer_rvq_rest_vq_layers_{l}__codebook_embedding_sum"),
                format!("{PFX}quantizer_rvq_rest_vq_layers_{l}__codebook_cluster_usage"),
            )
        }
    }

    // ── 3. pre_transformer ─────────────────────────────────────────────────
    //
    // Input is [decoder_in=1024, n_frames] (channel-major). input_proj 1024→512,
    // 8 transformer layers (RMSNorm pre-norm, GQA self-attn with rope, SwiGLU,
    // per-sublayer LayerScale), final norm, output_proj 512→1024.
    fn pre_transformer(&self, x_cm: &[f32], n: usize) -> Result<Vec<f32>, String> {
        let cfg = &self.cfg;
        let din = cfg.decoder_in; // 1024
        let h = cfg.pre_tf_hidden; // 512

        // input_proj: [512, 1024] (+ bias [512]). Operate per timestep on the
        // time-major view.
        let ip_w = self.fetch_f32(&format!("{PFX}pre_transformer_input_proj_weight"))?;
        let ip_b = self.fetch_f32(&format!("{PFX}pre_transformer_input_proj_bias"))?;
        let mut hs = vec![0.0f32; n * h]; // [n, h] time-major hidden state
        for t in 0..n {
            // gather x[:, t] into [din]
            let mut col = vec![0.0f32; din];
            for c in 0..din {
                col[c] = x_cm[c * n + t];
            }
            let dst = &mut hs[t * h..(t + 1) * h];
            mat_vec_f32(dst, &col, &ip_w, h, din);
            for o in 0..h {
                dst[o] += ip_b[o];
            }
        }

        // rope tables [n, head_dim] (full-rotation, interleaved-half form).
        let hd = cfg.pre_tf_head_dim;
        let (cos_t, sin_t) = build_rope(n, hd, cfg.rope_theta);

        for l in 0..cfg.pre_tf_layers {
            self.pre_tf_layer(&mut hs, l, n, &cos_t, &sin_t)?;
        }

        // final norm.
        let norm_w = self.fetch_f32(&format!("{PFX}pre_transformer_norm_weight"))?;
        for t in 0..n {
            let src = hs[t * h..(t + 1) * h].to_vec();
            rms_norm(&mut hs[t * h..(t + 1) * h], &src, &norm_w, cfg.rms_norm_eps);
        }

        // output_proj: [1024, 512] (+ bias [1024]) → back to channel-major [din, n].
        let op_w = self.fetch_f32(&format!("{PFX}pre_transformer_output_proj_weight"))?;
        let op_b = self.fetch_f32(&format!("{PFX}pre_transformer_output_proj_bias"))?;
        let mut out_cm = vec![0.0f32; din * n];
        for t in 0..n {
            let row = &hs[t * h..(t + 1) * h];
            let mut o = vec![0.0f32; din];
            mat_vec_f32(&mut o, row, &op_w, din, h);
            for c in 0..din {
                out_cm[c * n + t] = o[c] + op_b[c];
            }
        }
        Ok(out_cm)
    }

    fn pre_tf_layer(
        &self,
        hs: &mut [f32],
        l: usize,
        n: usize,
        cos_t: &[f32],
        sin_t: &[f32],
    ) -> Result<(), String> {
        let cfg = &self.cfg;
        let h = cfg.pre_tf_hidden;
        let nh = cfg.pre_tf_heads;
        let nkv = cfg.pre_tf_kv_heads;
        let hd = cfg.pre_tf_head_dim;
        let p = format!("{PFX}pre_transformer_layers_{l}_");

        // ── self-attention ──
        let in_ln = self.fetch_f32(&format!("{p}input_layernorm_weight"))?;
        let qw = self.fetch_f32(&format!("{p}self_attn_q_proj_weight"))?;
        let kw = self.fetch_f32(&format!("{p}self_attn_k_proj_weight"))?;
        let vw = self.fetch_f32(&format!("{p}self_attn_v_proj_weight"))?;
        let ow = self.fetch_f32(&format!("{p}self_attn_o_proj_weight"))?;
        let attn_scale = self.fetch_f32(&format!("{p}self_attn_layer_scale_scale"))?;

        let q_dim = nh * hd;
        let kv_dim = nkv * hd;
        let mut q = vec![0.0f32; n * q_dim];
        let mut k = vec![0.0f32; n * kv_dim];
        let mut v = vec![0.0f32; n * kv_dim];
        for t in 0..n {
            let src = hs[t * h..(t + 1) * h].to_vec();
            let mut xn = vec![0.0f32; h];
            rms_norm(&mut xn, &src, &in_ln, cfg.rms_norm_eps);
            mat_vec_f32(&mut q[t * q_dim..(t + 1) * q_dim], &xn, &qw, q_dim, h);
            mat_vec_f32(&mut k[t * kv_dim..(t + 1) * kv_dim], &xn, &kw, kv_dim, h);
            mat_vec_f32(&mut v[t * kv_dim..(t + 1) * kv_dim], &xn, &vw, kv_dim, h);
        }
        apply_rope_half(&mut q, cos_t, sin_t, n, nh, hd);
        apply_rope_half(&mut k, cos_t, sin_t, n, nkv, hd);

        // causal full attention (the decoder pre-transformer is causal).
        let group = nh / nkv;
        let scale = 1.0f32 / (hd as f32).sqrt();
        let mut attn_out = vec![0.0f32; n * q_dim];
        for head in 0..nh {
            let kvh = head / group;
            for tq in 0..n {
                let qv = &q[tq * q_dim + head * hd..tq * q_dim + head * hd + hd];
                let mut scores = vec![0.0f32; tq + 1];
                for tk in 0..=tq {
                    let kv = &k[tk * kv_dim + kvh * hd..tk * kv_dim + kvh * hd + hd];
                    let mut s = 0.0f32;
                    for d in 0..hd {
                        s += qv[d] * kv[d];
                    }
                    scores[tk] = s * scale;
                }
                softmax(&mut scores);
                let dst = &mut attn_out[tq * q_dim + head * hd..tq * q_dim + head * hd + hd];
                for tk in 0..=tq {
                    let vv = &v[tk * kv_dim + kvh * hd..tk * kv_dim + kvh * hd + hd];
                    let w = scores[tk];
                    for d in 0..hd {
                        dst[d] += w * vv[d];
                    }
                }
            }
        }
        // o_proj + LayerScale + residual.
        for t in 0..n {
            let mut o = vec![0.0f32; h];
            mat_vec_f32(&mut o, &attn_out[t * q_dim..(t + 1) * q_dim], &ow, h, q_dim);
            for c in 0..h {
                hs[t * h + c] += o[c] * attn_scale[c];
            }
        }

        // ── SwiGLU MLP ──
        let post_ln = self.fetch_f32(&format!("{p}post_attention_layernorm_weight"))?;
        let gate_w = self.fetch_f32(&format!("{p}mlp_gate_proj_weight"))?;
        let up_w = self.fetch_f32(&format!("{p}mlp_up_proj_weight"))?;
        let down_w = self.fetch_f32(&format!("{p}mlp_down_proj_weight"))?;
        let mlp_scale = self.fetch_f32(&format!("{p}mlp_layer_scale_scale"))?;
        let inter = cfg.pre_tf_inter;
        for t in 0..n {
            let src = hs[t * h..(t + 1) * h].to_vec();
            let mut xn = vec![0.0f32; h];
            rms_norm(&mut xn, &src, &post_ln, cfg.rms_norm_eps);
            let mut gate = vec![0.0f32; inter];
            let mut up = vec![0.0f32; inter];
            mat_vec_f32(&mut gate, &xn, &gate_w, inter, h);
            mat_vec_f32(&mut up, &xn, &up_w, inter, h);
            for i in 0..inter {
                let g = gate[i];
                gate[i] = (g / (1.0 + (-g).exp())) * up[i]; // SiLU(gate)·up
            }
            let mut down = vec![0.0f32; h];
            mat_vec_f32(&mut down, &gate, &down_w, h, inter);
            for c in 0..h {
                hs[t * h + c] += down[c] * mlp_scale[c];
            }
        }
        Ok(())
    }

    // ── 4. ConvNeXt upsample stage ─────────────────────────────────────────
    //
    // decoder.upsample.{si}.0 = conv_transpose1d stride 2 (k=2): channels in→out
    //   (both 1024). decoder.upsample.{si}.1 = ConvNeXt block.
    fn upsample_stage(
        &self,
        x_cm: &[f32],
        si: usize,
        ch: usize,
        in_len: usize,
        stride: usize,
    ) -> Result<(Vec<f32>, usize), String> {
        // conv_transpose1d k=stride, pad 0 → out_len = (in_len-1)*stride + k.
        let w = self.fetch_f32(&format!("{PFX}upsample_{si}_0_conv_weight"))?;
        let b = self.fetch_f32(&format!("{PFX}upsample_{si}_0_conv_bias"))?;
        let k = stride; // headers: weight [1024,1024,2] with stride 2
        let span = (in_len - 1) * stride + k;
        let out_len = span; // pad 0
        let mut up = vec![0.0f32; ch * out_len];
        conv_transpose1d(&mut up, x_cm, &w, Some(&b), ch, ch, in_len, k, stride, 0);
        // Trim trailing extra so length == in_len*stride (causal transposed conv
        // emits one extra frame; HF crops the right).
        let target = in_len * stride;
        let up = crop_right_cm(&up, ch, out_len, target);

        // ConvNeXt block (depthwise k7 causal → LN → pwconv1 4× → GELU → pwconv2
        // → ·gamma + residual).
        let out = self.convnext_block(&up, si, ch, target)?;
        Ok((out, target))
    }

    fn convnext_block(
        &self,
        x_cm: &[f32],
        si: usize,
        ch: usize,
        len: usize,
    ) -> Result<Vec<f32>, String> {
        let p = format!("{PFX}upsample_{si}_1_");
        // depthwise conv k7, groups=ch (weight [ch,1,7]), causal pad 6.
        let dw = self.fetch_f32(&format!("{p}dwconv_conv_weight"))?;
        let db = self.fetch_f32(&format!("{p}dwconv_conv_bias"))?;
        let mut h = vec![0.0f32; ch * len];
        depthwise_causal(&mut h, x_cm, &dw, Some(&db), ch, len, 7);

        // channel-last LayerNorm (over channel dim) → pwconv1 (ch→4ch) → GELU →
        // pwconv2 (4ch→ch). pwconv are Linear over the channel axis.
        let ln_w = self.fetch_f32(&format!("{p}norm_weight"))?;
        let ln_b = self.fetch_f32(&format!("{p}norm_bias"))?;
        let pw1_w = self.fetch_f32(&format!("{p}pwconv1_weight"))?; // [4ch, ch]
        let pw1_b = self.fetch_f32(&format!("{p}pwconv1_bias"))?;
        let pw2_w = self.fetch_f32(&format!("{p}pwconv2_weight"))?; // [ch, 4ch]
        let pw2_b = self.fetch_f32(&format!("{p}pwconv2_bias"))?;
        let gamma = self.fetch_f32(&format!("{p}gamma"))?;
        let inter = pw1_b.len(); // 4*ch

        let mut out = vec![0.0f32; ch * len];
        for t in 0..len {
            // gather channel vector at t.
            let mut cv = vec![0.0f32; ch];
            for c in 0..ch {
                cv[c] = h[c * len + t];
            }
            layernorm_inplace(&mut cv, &ln_w, &ln_b, 1e-6);
            let mut mid = vec![0.0f32; inter];
            mat_vec_f32(&mut mid, &cv, &pw1_w, inter, ch);
            for v in mid.iter_mut().zip(pw1_b.iter()) {
                *v.0 += *v.1;
            }
            gelu_inplace(&mut mid);
            let mut back = vec![0.0f32; ch];
            mat_vec_f32(&mut back, &mid, &pw2_w, ch, inter);
            for c in 0..ch {
                back[c] += pw2_b[c];
                // ·gamma (LayerScale) + residual (x BEFORE depthwise is the
                // ConvNeXt residual; here x_cm is that input).
                out[c * len + t] = x_cm[c * len + t] + back[c] * gamma[c];
            }
        }
        Ok(out)
    }

    // ── 5. SEANet decoder ──────────────────────────────────────────────────
    fn seanet_decode(&self, x_cm: &[f32], ch_in: usize, len_in: usize) -> Result<Vec<f32>, String> {
        let cfg = &self.cfg;
        // block 0: conv 1024→1536 k7 causal pad 6.
        let mut ch = 1536usize;
        let mut len = len_in;
        let mut x = self.causal_conv1d(
            x_cm,
            &format!("{PFX}decoder_0_conv"),
            ch_in,
            ch,
            len_in,
            7,
            1,
            1,
        )?;

        // blocks 1..4: Snake → conv_transpose upsample → 3 residual units.
        let block_out_ch = [768usize, 384, 192, 96];
        for (bi, &stride) in cfg.seanet_strides.iter().enumerate() {
            let block = bi + 1;
            let out_ch = block_out_ch[bi];

            // block.0 Snake (alpha/beta dim == ch).
            self.snake(&mut x, block, 0, ch, len)?;

            // block.1 conv_transpose1d, k = 2*stride. The OFFICIAL reference
            // CausalTransConvNet (Qwen3TTSTokenizerV2CausalTransConvNet) does:
            //   y = conv_transpose1d(x, k, stride, pad=0)   # len → (len-1)*stride + k
            //   right_pad = k - stride
            //   y = y[..., : y.len - right_pad]              # crop RIGHT only (causal)
            // → final length (len-1)*stride + k - (k-stride) = len*stride. Keep
            // the LEFT (causal) portion. (NOT the symmetric crop the ggml port used.)
            let k = 2 * stride;
            let w = self.fetch_f32(&format!("{PFX}decoder_{block}_block_1_conv_weight"))?; // [ch_in, out_ch, k]
            let b = self.fetch_f32(&format!("{PFX}decoder_{block}_block_1_conv_bias"))?;
            let raw_len = (len - 1) * stride + k; // pad=0 transposed-conv length
            let mut up = vec![0.0f32; out_ch * raw_len];
            conv_transpose1d(&mut up, &x, &w, Some(&b), ch, out_ch, len, k, stride, 0);
            let target = len * stride; // == raw_len - (k - stride)
            x = crop_right_cm(&up, out_ch, raw_len, target);
            len = target;
            ch = out_ch;

            // 3 residual units (block.2, block.3, block.4), dilations [1,3,9].
            for (ui, &dil) in cfg.seanet_dilations.iter().enumerate() {
                let unit = ui + 2; // block.2 / block.3 / block.4
                let res = x.clone();
                // act1 Snake → conv1 k7 dilated (causal) → act2 Snake → conv2 k1.
                self.snake_unit(&mut x, block, unit, "act1", ch, len)?;
                x = self.causal_conv1d(
                    &x,
                    &format!("{PFX}decoder_{block}_block_{unit}_conv1_conv"),
                    ch,
                    ch,
                    len,
                    7,
                    1,
                    dil,
                )?;
                self.snake_unit(&mut x, block, unit, "act2", ch, len)?;
                x = self.causal_conv1d(
                    &x,
                    &format!("{PFX}decoder_{block}_block_{unit}_conv2_conv"),
                    ch,
                    ch,
                    len,
                    1,
                    1,
                    1,
                )?;
                // residual add.
                for i in 0..x.len() {
                    x[i] += res[i];
                }
            }
        }

        // block 5: final Snake (ch=96).
        self.snake(&mut x, 5, usize::MAX, ch, len)?;

        // block 6: conv 96→1 k7 causal, then the OFFICIAL final activation:
        // wav.clamp(min=-1, max=1) (Qwen3TTSTokenizerV2Decoder.forward). NOT tanh
        // (the ggml port used tanh; the reference hard-clamps).
        let mut wav = self.causal_conv1d(&x, &format!("{PFX}decoder_6_conv"), ch, 1, len, 7, 1, 1)?;
        for s in wav.iter_mut() {
            *s = s.clamp(-1.0, 1.0);
        }
        Ok(wav) // [1, len] == [len]
    }

    // ── helpers ─────────────────────────────────────────────────────────────

    /// Causal conv1d: left-pad (k-1)*dilation, no right pad, trim to in_len.
    /// Operates on channel-major [in_ch, in_len], returns [out_ch, in_len].
    #[allow(clippy::too_many_arguments)]
    fn causal_conv1d(
        &self,
        x_cm: &[f32],
        name: &str,
        in_ch: usize,
        out_ch: usize,
        in_len: usize,
        k: usize,
        stride: usize,
        dilation: usize,
    ) -> Result<Vec<f32>, String> {
        let w = self.fetch_f32(&format!("{name}_weight"))?;
        let b = self.fetch_f32(&format!("{name}_bias")).ok();
        let left = (k - 1) * dilation;
        // build left-padded input [in_ch, in_len + left].
        let plen = in_len + left;
        let mut xp = vec![0.0f32; in_ch * plen];
        for c in 0..in_ch {
            for t in 0..in_len {
                xp[c * plen + (t + left)] = x_cm[c * in_len + t];
            }
        }
        let out_len = conv1d_out_len_dilated(plen, k, stride, 0, dilation);
        let mut out = vec![0.0f32; out_ch * out_len];
        conv1d_dilated(
            &mut out,
            &xp,
            &w,
            b.as_deref(),
            in_ch,
            out_ch,
            plen,
            k,
            stride,
            0,
            dilation,
        );
        // causal conv keeps the first in_len/stride outputs.
        let keep = in_len / stride;
        let out = crop_right_cm(&out, out_ch, out_len, keep.min(out_len));
        Ok(out)
    }

    /// Snake-beta activation in place on a [ch, len] buffer using
    /// decoder.{block}.{?}.alpha/beta (block.0 / block.5 carry top-level
    /// alpha/beta; residual units carry act{1,2}.alpha/beta).
    fn snake(
        &self,
        x: &mut [f32],
        block: usize,
        sub: usize,
        ch: usize,
        len: usize,
    ) -> Result<(), String> {
        // Upsample blocks 1-4 nest the top Snake at decoder.{block}.block.0.* →
        // knot name decoder_{block}_block_{sub}_*. Block 5 is a bare Snake
        // (decoder_5_*), signalled by sub == usize::MAX.
        let (alpha_name, beta_name) = if sub == usize::MAX {
            (
                format!("{PFX}decoder_{block}_alpha"),
                format!("{PFX}decoder_{block}_beta"),
            )
        } else {
            (
                format!("{PFX}decoder_{block}_block_{sub}_alpha"),
                format!("{PFX}decoder_{block}_block_{sub}_beta"),
            )
        };
        let alpha = self.fetch_f32(&alpha_name)?;
        let beta = self.fetch_f32(&beta_name)?;
        apply_snake_beta(x, &alpha, &beta, ch, len);
        Ok(())
    }

    fn snake_unit(
        &self,
        x: &mut [f32],
        block: usize,
        unit: usize,
        act: &str,
        ch: usize,
        len: usize,
    ) -> Result<(), String> {
        let alpha = self.fetch_f32(&format!("{PFX}decoder_{block}_block_{unit}_{act}_alpha"))?;
        let beta = self.fetch_f32(&format!("{PFX}decoder_{block}_block_{unit}_{act}_beta"))?;
        apply_snake_beta(x, &alpha, &beta, ch, len);
        Ok(())
    }

    fn fetch_f32(&self, name: &str) -> Result<Vec<f32>, String> {
        let bytes = self
            .backend
            .fetch_tensor(name)
            .map_err(|e| format!("{name}: {e}"))?;
        let qtype = self
            .backend
            .tensor_info(name)
            .map(|ti| ti.tensor_type.to_ascii_lowercase())
            .unwrap_or_else(|| "f32".to_string());
        match qtype.as_str() {
            "q8_0" => {
                let n_elems = (bytes.len() / 34) * 32;
                let mut out = vec![0f32; n_elems];
                crate::math::dequantize_q8_0_row(&mut out, &bytes, 0, n_elems);
                Ok(out)
            }
            "f32" | "fp32" => Ok(bytes_to_f32(&bytes).to_vec()),
            other => Err(format!(
                "fetch_f32 {name}: unsupported codec qtype '{other}'"
            )),
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// free functions
// ─────────────────────────────────────────────────────────────────────────────

fn bytes_to_f32(bytes: &[u8]) -> &[f32] {
    assert!(
        bytes.len().is_multiple_of(4),
        "bytes_to_f32: len {} not /4",
        bytes.len()
    );
    unsafe { std::slice::from_raw_parts(bytes.as_ptr() as *const f32, bytes.len() / 4) }
}

/// Crop a [ch, cur_len] channel-major buffer to [ch, target] keeping the LEFT
/// (causal) portion.
fn crop_right_cm(buf: &[f32], ch: usize, cur_len: usize, target: usize) -> Vec<f32> {
    if target == cur_len {
        return buf.to_vec();
    }
    let mut out = vec![0.0f32; ch * target];
    for c in 0..ch {
        for t in 0..target {
            out[c * target + t] = buf[c * cur_len + t];
        }
    }
    out
}

/// Snake-beta — EXACT official Qwen3-TTS SnakeBeta.forward: α and β are stored
/// in LOG space; the effective gains are exp(α) and 1/(exp(β)+ε):
///   y = x + (1/(exp(β) + 1e-9)) · sin²(exp(α) · x)
/// per-channel α, β. Channel-major.
fn apply_snake_beta(x: &mut [f32], alpha: &[f32], beta: &[f32], ch: usize, len: usize) {
    let no_div_by_zero = 1e-9f32;
    for c in 0..ch {
        let a = alpha[c].exp();
        let inv_b = 1.0 / (beta[c].exp() + no_div_by_zero);
        for t in 0..len {
            let v = x[c * len + t];
            let s = (a * v).sin();
            x[c * len + t] = v + inv_b * s * s;
        }
    }
}

/// Depthwise causal conv (groups == ch), weight [ch, 1, k], left-pad k-1.
fn depthwise_causal(
    out: &mut [f32],
    x_cm: &[f32],
    w: &[f32],
    b: Option<&[f32]>,
    ch: usize,
    len: usize,
    k: usize,
) {
    let left = k - 1;
    for c in 0..ch {
        let bias = b.map(|bb| bb[c]).unwrap_or(0.0);
        for t in 0..len {
            let mut acc = bias;
            for kk in 0..k {
                let src = t as isize + kk as isize - left as isize;
                if src < 0 || src as usize >= len {
                    continue;
                }
                acc += x_cm[c * len + src as usize] * w[c * k + kk];
            }
            out[c * len + t] = acc;
        }
    }
}

/// LayerNorm over a single channel vector (mean/var over the vector), in place.
fn layernorm_inplace(v: &mut [f32], w: &[f32], b: &[f32], eps: f32) {
    let n = v.len() as f32;
    let mean: f32 = v.iter().sum::<f32>() / n;
    let var: f32 = v.iter().map(|x| (x - mean) * (x - mean)).sum::<f32>() / n;
    let inv = 1.0 / (var + eps).sqrt();
    for i in 0..v.len() {
        v[i] = (v[i] - mean) * inv * w[i] + b[i];
    }
}

/// Build interleaved-half rope cos/sin tables [n, head_dim].
fn build_rope(n: usize, head_dim: usize, theta: f32) -> (Vec<f32>, Vec<f32>) {
    let half = head_dim / 2;
    let mut cos = vec![0.0f32; n * head_dim];
    let mut sin = vec![0.0f32; n * head_dim];
    for pos in 0..n {
        for i in 0..half {
            let freq = 1.0 / theta.powf((2 * i) as f32 / head_dim as f32);
            let ang = pos as f32 * freq;
            let (s, c) = ang.sin_cos();
            cos[pos * head_dim + i] = c;
            cos[pos * head_dim + i + half] = c;
            sin[pos * head_dim + i] = s;
            sin[pos * head_dim + i + half] = s;
        }
    }
    (cos, sin)
}

/// Apply rotate-half rope in place on [n, n_heads*head_dim].
fn apply_rope_half(
    buf: &mut [f32],
    cos: &[f32],
    sin: &[f32],
    n: usize,
    n_heads: usize,
    head_dim: usize,
) {
    let h = n_heads * head_dim;
    let half = head_dim / 2;
    for t in 0..n {
        let cb = t * head_dim;
        for head in 0..n_heads {
            let base = t * h + head * head_dim;
            for i in 0..half {
                let x0 = buf[base + i];
                let x1 = buf[base + i + half];
                let c = cos[cb + i];
                let s = sin[cb + i];
                buf[base + i] = x0 * c - x1 * s;
                buf[base + i + half] = x1 * c + x0 * s;
            }
        }
    }
}
